export function createApiResponseClass(DataDto: Type): Type<ApiResponse> {
  class ResponseClass implements ApiResponse {
    @ApiProperty({ example: true })
    success: boolean;

    @ApiProperty({ example: 200 })
    status: number;

    @ApiProperty({ type: DataDto })
    data: T;

    @ApiProperty({ example: 'Operation successful' })
    message: string;
  }

  Object.defineProperty(ResponseClass, 'name', {
    value: `${DataDto.name}Response`,
  });

  return ResponseClass;
}

export function createPaginatedApiResponseClass(DataDto: Type): Type<PaginatedApiResponse> {
  class PaginatedResponseClass implements PaginatedApiResponse {
    @ApiProperty({ example: true })
    success: boolean;

    @ApiProperty({ example: 200 })
    status: number;

    @ApiProperty({ type: [DataDto] })
    data: T[];

    @ApiProperty({ example: 150 })
    count: number;

    @ApiProperty({ example: 'Operation successful' })
    message: string;
  }

  Object.defineProperty(PaginatedResponseClass, 'name', {
    value: `${DataDto.name}PaginatedResponse`,
  });

  return PaginatedResponseClass;
}

export class ErrorApiResponseClass {
  @ApiProperty({ example: false })
  success: boolean;

  @ApiProperty({ example: 400 })
  status: number;

  @ApiProperty({ example: 'Validation failed' })
  message: string;

  @ApiProperty({
    example: ['field must be a string'],
    required: false,
  })
  errors?: string[];
}
